<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Autonomous Maze Bots</title>
    <style>
        body {
            background-color: #121212;
            color: #e0e0e0;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            margin: 0;
            overflow: hidden;
        }

        #hud {
            margin-bottom: 20px;
            padding: 15px 30px;
            background: #1e1e1e;
            border-radius: 8px;
            box-shadow: 0 4px 15px rgba(0,0,0,0.5);
            display: flex;
            gap: 40px;
            border: 1px solid #333;
        }

        .stat {
            font-size: 1.2rem;
            font-weight: bold;
        }

        #maze {
            border: 4px solid #333;
            background-color: #000;
            box-shadow: 0 0 20px rgba(0,0,0,0.8);
            image-rendering: pixelated;
        }

        #reset {
            margin-top: 20px;
            padding: 10px 25px;
            font-size: 1rem;
            background-color: #cf6679;
            color: white;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            transition: background 0.2s;
        }

        #reset:hover {
            background-color: #ff8a80;
        }

        span { color: #03dac6; }
    </style>
</head>
<body>

    <div id="hud">
        <div class="stat">Completed: <span id="completed">0</span> / 24</div>
        <div class="stat">Time: <span id="timer">0</span>ms</div>
    </div>

    <canvas id="maze" width="400" height="400"></canvas>

    <button id="reset">Restart Game</button>

    <script>
        /**
         * GAME CONFIGURATION & STATE
         */
        const CELL_COUNT = 15; // Logical maze size (15x15)
        const GRID_SIZE = CELL_COUNT * 2 + 1; // Physical grid for walls/paths
        const CANVAS_SIZE = 400;
        const BOT_COUNT = 24;
        const TICK_MS = 33; // Simulation step duration

        let mazeGrid = [];
        let startPos = { x: 1, y: 1 };
        let exitPos = { x: GRID_SIZE - 2, y: GRID_SIZE - 2 };
        let bots = [];
        let completedCount = 0;
        let elapsedMs = 0;

        const canvas = document.getElementById('maze');
        const ctx = canvas.getContext('2d');
        const completedEl = document.getElementById('completed');
        const timerEl = document.getElementById('timer');
        const resetBtn = document.getElementById('reset');

        /**
         * MAZE GENERATION (Recursive Backtracker)
         */
        function generateMaze() {
            // Initialize grid with walls (1)
            mazeGrid = Array(GRID_SIZE).fill().map(() => Array(GRID_SIZE).fill(1));

            const stack = [[1, 1]];
            mazeGrid[1][1] = 0; // Path cell

            while (stack.length > 0) {
                const [x, y] = stack[stack.length - 1];
                const neighbors = [];

                // Check 4 directions (2 units away to leave walls in between)
                const dirs = [[0, 2], [0, -2], [2, 0], [-2, 0]];
                for (let [dx, dy] of dirs) {
                    const nx = x + dx;
                    const ny = y + dy;
                    if (nx > 0 && nx < GRID_SIZE - 1 && ny > 0 && ny < GRID_SIZE - 1 && mazeGrid[ny][nx] === 1) {
                        neighbors.push([nx, ny]);
                    }
                }

                if (neighbors.length > 0) {
                    const [nx, ny] = neighbors[Math.floor(Math.random() * neighbors.length)];
                    mazeGrid[ny][nx] = 0; // Carve path to neighbor
                    mazeGrid[y + (ny - y) / 2][x + (nx - x) / 2] = 0; // Remove wall between
                    stack.push([nx, ny]);
                } else {
                    stack.pop();
                }
            }

            // Ensure start and exit are clear
            mazeGrid[startPos.y][startPos.x] = 0;
            mazeGrid[exitPos.y][exitPos.x] = 0;
        }

        /**
         * PATHFINDING (BFS)
         */
        function findPath(start, end) {
            const queue = [[start]];
            const visited = new Set();
            visited.add(`${start.x},${start.y}`);

            while (queue.length > 0) {
                const path = queue.shift();
                const curr = path[path.length - 1];

                if (curr.x === end.x && curr.y === end.y) return path;

                const dirs = [[0, 2], [0, -2], [2, 0], [-2, 0]];
                for (let [dx, dy] of dirs) {
                    const nx = curr.x + dx;
                    const ny = curr.y + dy;
                    if (nx > 0 && nx < GRID_SIZE - 1 && ny > 0 && ny < GRID_SIZE - 1 &&
                        mazeGrid[ny][nx] === 0 && !visited.has(`${nx},${ny}`)) {
                        visited.add(`${nx},${ny}`);
                        queue.push([...path, { x: nx, y: ny }]);
                    }
                }
            }
            return [];
        }

        /**
         * RENDERING
         */
        function render() {
            ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);
            const cellSize = CANVAS_SIZE / GRID_SIZE;

            // Draw Maze
            for (let y = 0; y < GRID_SIZE; y++) {
                for (let x = 0; x < GRID_SIZE; x++) {
                    if (mazeGrid[y][x] === 1) {
                        ctx.fillStyle = '#333';
                        ctx.fillRect(x * cellSize, y * cellSize, cellSize, cellSize);
                    }
                }
            }

            // Draw Start/Exit
            ctx.fillStyle = '#4caf50'; // Green start
            ctx.fillRect(startPos.x * cellSize, startPos.y * cellSize, cellSize, cellSize);
            ctx.fillStyle = '#f44336'; // Red exit
            ctx.fillRect(exitPos.x * cellSize, exitPos.y * cellSize, cellSize, cellSize);

            // Draw Bots
            bots.forEach((bot, i) => {
                ctx.fillStyle = `hsl(${i * (360 / BOT_COUNT)}, 70%, 60%)`;
                ctx.beginPath();
                ctx.arc(
                    bot.x * cellSize + cellSize / 2,
                    bot.y * cellSize + cellSize / 2,
                    cellSize / 3,
                    0, Math.PI * 2
                );
                ctx.fill();
            });

            // Update HUD
            completedEl.innerText = completedCount;
            timerEl.innerText = elapsedMs;
        }

        /**
         * GAME ENGINE & API
         */
        const game = {
            bots: [],
            completed: 0, // This will be updated by the logic, but we'll use a getter or direct access
            elapsedMs: 0,

            get completed() { return completedCount; },

            init() {
                generateMaze();
                completedCount = 0;
                elapsedMs = 0;
                bots = [];

                for (let i = 0; i < BOT_COUNT; i++) {
                    const path = findPath(startPos, exitPos);
                    bots.push({
                        x: startPos.x,
                        y: startPos.y,
                        path: path,
                        pathIndex: 0,
                        delay: Math.floor(Math.random() * 40), // Staggered starts
                        finished: false
                    });
                }
                render();
            },

            tick(n) {
                for (let i = 0; i < n; i++) {
                    bots.forEach(bot => {
                        if (!bot.finished) {
                            if (bot.delay > 0) {
                                bot.delay--;
                            } else {
                                const next = bot.path[bot.pathIndex + 1];
                                if (next) {
                                    bot.x = next.x;
                                    bot.y = next.y;
                                    bot.pathIndex++;
                                    if (bot.x === exitPos.x && bot.y === exitPos.y) {
                                        bot.finished = true;
                                        completedCount++;
                                    }
                                }
                            }
                        }
                    });
                    elapsedMs += TICK_MS;
                }
                render();
            },

            reset() {
                this.init();
            }
        };

        // Expose to window for grading
        window.game = game;

        /**
         * EVENT LISTENERS & LOOP
         */
        resetBtn.addEventListener('click', () => game.reset());

        // Initial Start
        game.init();

        // Animation Loop
        function loop() {
            game.tick(1);
            requestAnimationFrame(loop);
        }
        requestAnimationFrame(loop);

    </script>
</body>
</html>
